# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>

using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;  // 26 pointers for 'a' to 'z'
    bool isEndOfWord;

    TrieNode() : isEndOfWord(false) {
        children.resize(26, nullptr);  // Initialize with 26 null pointers
    }
};

class Trie {
private:
    TrieNode* root;

public:
    // Constructor
    Trie() {
        root = new TrieNode();
    }

    // Destructor
    ~Trie() {
        deleteTrieNode(root);
    }

    // Helper function to delete the trie
    void deleteTrieNode(TrieNode* node) {
        if (!node) return;

        for (int i = 0; i < 26; i++) {
            if (node->children[i]) {
                deleteTrieNode(node->children[i]);
            }
        }
        delete node;
    }

    // Insert a word into the trie
    void insert(const string& word) {
        TrieNode* current = root;

        for (char ch : word) {
            int index = ch - 'a';  // Convert char to index (0-25)

            // If the child doesn't exist, create a new node
            if (!current->children[index]) {
                current->children[index] = new TrieNode();
            }

            current = current->children[index];
        }

        // Mark the end of the word
        current->isEndOfWord = true;
    }

    // Search for a complete word
    bool search(const string& word) const {
        TrieNode* node = findNode(word);
        return node != nullptr && node->isEndOfWord;
    }

    // Search for a prefix
    bool startsWith(const string& prefix) const {
        return findNode(prefix) != nullptr;
    }

    // Helper function to find a node
    private:
    TrieNode* findNode(const string& str) const {
        TrieNode* current = root;

        for (char ch : str) {
            int index = ch - 'a';

            if (!current->children[index]) {
                return nullptr;
            }

            current = current->children[index];
        }

        return current;
    }

public:
    // Delete a word from the trie
    bool deleteWord(const string& word) {
        return deleteHelper(root, word, 0);
    }

    private:
    bool deleteHelper(TrieNode* node, const string& word, int index) {
        if (!node) return false;

        if (index == word.length()) {
            // If the word is not in trie, return false
            if (!node->isEndOfWord) return false;

            // Mark the node as not end of word
            node->isEndOfWord = false;

            // Return true if the node has no children (can be deleted)
            for (int i = 0; i < 26; i++) {
                if (node->children[i]) return false;
            }
            return true;
        }

        int childIndex = word[index] - 'a';
        TrieNode* childNode = node->children[childIndex];

        if (!childNode) return false;

        bool shouldDeleteChild = deleteHelper(childNode, word, index + 1);

        if (shouldDeleteChild) {
            delete childNode;
            node->children[childIndex] = nullptr;

            // Return true if the current node can also be deleted
            return !node->isEndOfWord && isEmpty(node);
        }

        return false;
    }

    bool isEmpty(TrieNode* node) const {
        for (int i = 0; i < 26; i++) {
            if (node->children[i]) return false;
        }
        return true;
    }

public:
    // Display all words in the trie
    void displayAll() {
        string result = "";
        displayHelper(root, result);
    }

    private:
    void displayHelper(TrieNode* node, string& word) {
        if (!node) return;

        if (node->isEndOfWord) {
            cout << word << endl;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i]) {
                word.push_back('a' + i);
                displayHelper(node->children[i], word);
                word.pop_back();
            }
        }
    }
};

// Main function with examples
int main() {
    Trie trie;

    // Insert words
    cout << "=== Inserting Words ===" << endl;
    trie.insert("apple");
    trie.insert("app");
    trie.insert("apricot");
    trie.insert("banana");
    trie.insert("band");
    trie.insert("can");
    trie.insert("cat");
    cout << "Words inserted successfully!\n" << endl;

    // Search for complete words
    cout << "=== Search Results ===" << endl;
    cout << "Search 'apple': " << (trie.search("apple") ? "Found" : "Not Found") << endl;
    cout << "Search 'app': " << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Search 'appl': " << (trie.search("appl") ? "Found" : "Not Found") << endl;
    cout << "Search 'banana': " << (trie.search("banana") ? "Found" : "Not Found") << endl;
    cout << "Search 'bat': " << (trie.search("bat") ? "Found" : "Not Found") << endl << endl;

    // Search for prefixes
    cout << "=== Prefix Search ===" << endl;
    cout << "Prefix 'app': " << (trie.startsWith("app") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'ban': " << (trie.startsWith("ban") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'bat': " << (trie.startsWith("bat") ? "Found" : "Not Found") << endl << endl;

    // Display all words
    cout << "=== All Words in Trie ===" << endl;
    trie.displayAll();
    cout << endl;

    // Delete a word
    cout << "=== After Deleting 'app' ===" << endl;
    trie.deleteWord("app");
    trie.displayAll();

    return 0;
}
```

