# Dynamic MongoDB Query for User Data Filtering

Here are multiple approaches to filter the `user_data` table for male users:

## 1. **Basic Query (Simple)**
```javascript
db.user_data.find({ gender: "Male" })
```

## 2. **With Projection (Exclude sensitive data)**
```javascript
db.user_data.find(
  { gender: "Male" },
  { username: 1, gender: 1, _id: 0 }
)
```

## 3. **Dynamic Query Function (JavaScript)**
```javascript
function filterUserData(filterField, filterValue) {
  const query = {};
  query[filterField] = filterValue;
  return db.user_data.find(query).toArray();
}

// Usage
filterUserData("gender", "Male");
```

## 4. **Case-Insensitive & Dynamic Query**
```javascript
function dynamicFilter(field, value, caseSensitive = false) {
  const query = caseSensitive 
    ? { [field]: value }
    : { [field]: { $regex: `^${value}$`, $options: "i" } };

  return db.user_data.find(query);
}

// Usage
dynamicFilter("gender", "male");  // Works with any case
```

## 5. **With Pagination & Sorting**
```javascript
function filterWithPagination(field, value, page = 1, limit = 10) {
  const skip = (page - 1) * limit;

  return db.user_data
    .find({ [field]: value })
    .skip(skip)
    .limit(limit)
    .sort({ username: 1 })
    .toArray();
}

// Usage
filterWithPagination("gender", "Male", 2, 20);
```

## 6. **Advanced Query with Multiple Filters**
```javascript
function advancedFilter(filters = {}) {
  const query = {};

  Object.keys(filters).forEach(key => {
    if (filters[key] !== null && filters[key] !== undefined) {
      query[key] = filters[key];
    }
  });

  return db.user_data.find(query);
}

// Usage
advancedFilter({ gender: "Male", username: "john" });
```

## 7. **Node.js / Mongoose Example**
```javascript
const mongoose = require('mongoose');

// Schema
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const User = mongoose.model('user_data', userSchema);

// Dynamic filter function
async function filterUsers(filterObj) {
  try {
    const users = await User.find(filterObj).exec();
    return users;
  } catch (err) {
    console.error(err);
  }
}

// Usage
filterUsers({ gender: "Male" });
```

## 8. **Express.js API Endpoint**
```javascript
app.get('/users', async (req, res) => {
  try {
    const { gender, username } = req.query;
    const filter = {};

    if (gender) filter.gender = gender;
    if (username) filter.username = new RegExp(username, 'i');

