# Breadth-First Search (BFS) in C++

Here's a comprehensive implementation of BFS:

## 1. **Basic BFS with Adjacency List**

```cpp
#include <iostream>
#include <queue>
#include <vector>
using namespace std;

void bfs(int start, vector<vector<int>>& adj, vector<bool>& visited) {
    queue<int> q;
    q.push(start);
    visited[start] = true;

    while (!q.empty()) {
        int node = q.front();
        q.pop();
        cout << node << " ";

        // Visit all adjacent nodes
        for (int neighbor : adj[node]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                q.push(neighbor);
            }
        }
    }
}

int main() {
    int vertices = 6;
    vector<vector<int>> adj(vertices);

    // Add edges
    adj[0] = {1, 2};
    adj[1] = {0, 3, 4};
    adj[2] = {0, 5};
    adj[3] = {1};
    adj[4] = {1};
    adj[5] = {2};

    vector<bool> visited(vertices, false);

    cout << "BFS starting from vertex 0: ";
    bfs(0, adj, visited);
    cout << endl;

    return 0;
}
```

**Output:**
```
BFS starting from vertex 0: 0 1 2 3 4 5
```

