## 3. **BFS with Distance Tracking**

```cpp
#include <iostream>
#include <queue>
#include <vector>
using namespace std;

void bfsDistance(int start, vector<vector<int>>& adj, int vertices) {
    vector<int> dist(vertices, -1);
    queue<int> q;
    q.push(start);
    dist[start] = 0;

    while (!q.empty()) {
        int node = q.front();
        q.pop();

        for (int neighbor : adj[node]) {
            if (dist[neighbor] == -1) {
                dist[neighbor] = dist[node] + 1;
                q.push(neighbor);
            }
        }
    }

    cout << "Distance from vertex " << start << ":" << endl;
    for (int i = 0; i < vertices; i++) {
        cout << "Vertex " << i << ": " << dist[i] << endl;
    }
}

int main() {
    int vertices = 6;
    vector<vector<int>> adj(vertices);

    adj[0] = {1, 2};
    adj[1] = {0, 3, 4};
    adj[2] = {0, 5};
    adj[3] = {1};
    adj[4] = {1};
    adj[5] = {2};

    bfsDistance(0, adj, vertices);

    return 0;
}
