## 4. **BFS with Path Reconstruction**

```cpp
#include <iostream>
#include <queue>
#include <vector>
using namespace std;

void bfsPath(int start, vector<vector<int>>& adj, int vertices) {
    vector<int> parent(vertices, -1);
    vector<bool> visited(vertices, false);
    queue<int> q;
    q.push(start);
    visited[start] = true;

    while (!q.empty()) {
        int node = q.front();
        q.pop();

        for (int neighbor : adj[node]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                parent[neighbor] = node;
                q.push(neighbor);
            }
        }
    }

    // Print path to each vertex
    for (int i = 0; i < vertices; i++) {
        if (visited[i]) {
            cout << "Path from " << start << " to " << i << ": ";
            int curr = i;
            vector<int> path;
            while (curr != -1) {
                path.push_back(curr);
                curr = parent[curr];
            }
            for (int j = path.size() - 1; j >= 0; j--) {
                cout << path[j] << " ";
            }
            cout << endl;
        }
    }
}

int main() {
    int vertices = 6;
    vector<vector<int>> adj(vertices);

    adj[0] = {1, 2};
    adj[1] = {0, 3, 4};
    adj[2] = {0, 5};
    adj[3] = {1};
    adj[4] = {1};
    adj[5] = {2};

    bfsPath(0, adj, vertices);

    return 0;
}
```

**Output:**
```
Path from 0 to 0: 0
Path from 0 to 1: 0 1
Path from 0 to 2: 0 2
Path from 0 to 3: 0 1 3
Path from 0 to 4: 0 1 4
Path from 0 to 5: 0 2 5
```

