# Email Spam Classifier

I'll create a comprehensive program to predict whether an email is spam using machine learning.

```python
import numpy as np
import pandas as pd
from sklearn.model_selection import train_test_split
from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.naive_bayes import MultinomialNB
from sklearn.ensemble import RandomForestClassifier
from sklearn.pipeline import Pipeline
from sklearn.metrics import (
    accuracy_score, precision_score, recall_score, 
    f1_score, confusion_matrix, classification_report, roc_auc_score
)
import pickle
import re
import warnings
warnings.filterwarnings('ignore')

class EmailSpamClassifier:
    """
    A machine learning-based email spam classifier.
    """

    def __init__(self, model_type='naive_bayes'):
        """
        Initialize the classifier.

        Args:
            model_type (str): 'naive_bayes' or 'random_forest'
        """
        self.model_type = model_type
        self.pipeline = None
        self.is_trained = False

    def preprocess_text(self, text):
        """
        Preprocess email text.

        Args:
            text (str): Raw email text

        Returns:
            str: Cleaned text
        """
        # Convert to lowercase
        text = text.lower()

        # Remove URLs
        text = re.sub(r'http\S+|www\S+|https\S+', '', text, flags=re.MULTILINE)

        # Remove email addresses
        text = re.sub(r'\S+@\S+', '', text)

        # Remove special characters and digits
        text = re.sub(r'[^a-zA-Z\s]', '', text)

        # Remove extra whitespace
        text = ' '.join(text.split())

        return text

    def build_pipeline(self):
        """Build the ML pipeline."""
        if self.model_type == 'naive_bayes':
            classifier = MultinomialNB()
        elif self.model_type == 'random_forest':
            classifier = RandomForestClassifier(
                n_estimators=100,
                max_depth=10,
                random_state=42,
                n_jobs=-1
            )
        else:
            raise ValueError("model_type must be 'naive_bayes' or 'random_forest'")

        self.pipeline = Pipeline([
            ('tfidf', TfidfVectorizer(
                max_features=5000,
                stop_words='english',
                ngram_range=(1, 2),
                min_df=2,
                max_df=0.8
            )),
            ('classifier', classifier)
        ])

    def train(self, texts, labels):
        """
        Train the spam classifier.

        Args:
            texts (list): List of email texts
            labels (list): List of labels (0=ham, 1=spam)
        """
        print("Building pipeline...")
        self.build_pipeline()

        print("Preprocessing texts...")
        processed_texts = [self.preprocess_text(text) for text in texts]

        print("Training model...")
        self.pipeline.fit(processed_texts, labels)

        self.is_trained = True
        print("✓ Model trained successfully!")

    def predict(self, text):
        """
        Predict if email is spam.

        Args:
            text (str): Email text

        Returns:
            dict: Prediction results
        """
        if not self.is_trained:
            raise ValueError("Model must be trained first!")

        processed_text = self.preprocess_text(text)
        prediction = self.pipeline.predict([processed_text])[0]
        probability = self.pipeline.predict_proba([processed_text])[0]

        return {
            'is_spam': bool(prediction),
            'spam_probability': float(probability[1]),
            'ham_probability': float(probability[0]),
            'confidence': float(max(probability))
        }

    def predict_batch(self, texts):
        """
        Predict for multiple emails.

        Args:
            texts (list): List of email texts

        Returns:
            list: List of prediction dictionaries
        """
        return [self.predict(text) for text in texts]

    def evaluate(self, texts, labels):
        """
        Evaluate model performance.

        Args:
            texts (list): Email texts
            labels (list): True labels

        Returns:
            dict: Performance metrics
        """
        if not self.is_trained:
            raise ValueError("Model must be trained first!")

        processed_texts = [self.preprocess_text(text) for text in texts]
        predictions = self.pipeline.predict(processed_texts)
        probabilities = self.pipeline.predict_proba(processed_texts)[:, 1]

        metrics = {
            'accuracy': accuracy_score(labels, predictions),
            'precision': precision_score(labels, predictions),
            'recall': recall_score(labels, predictions),
            'f1_score': f1_score(labels, predictions),
            'roc_auc': roc_auc_score(labels, probabilities),
            'confusion_matrix': confusion_matrix(labels, predictions).tolist(),
            'classification_report': classification_report(labels, predictions)
        }

        return metrics

    def save_model(self, filepath):
        """Save trained model to file."""
        if not self.is_trained:
            raise ValueError("Model must be trained first!")

        with open(filepath, 'wb') as f:
            pickle.dump(self.pipeline, f)
        print(f"✓ Model saved to {filepath}")

    def load_model(self, filepath):
        """Load trained model from file."""
        with open(filepath, 'rb') as f:
            self.pipeline = pickle.load(f)
        self.is_trained = True
        print(f"✓ Model loaded from {filepath}")


