    classifier.train(texts, labels)
    classifier.save_model('spam_classifier_model.pkl')


@app.route('/')
def home():
    return render_template('index.html')


@app.route('/predict', methods=['POST'])
def predict():
    """API endpoint for spam prediction."""
    data = request.json
    email_text = data.get('email_text', '')

    if not email_text:
        return jsonify({'error': 'Email text is required'}), 400

    result = classifier.predict(email_text)

    return jsonify({
        'is_spam': result['is_spam'],
        'spam_probability': round(result['spam_probability'], 3),
        'confidence': round(result['confidence'], 3),
        'message': 'This email appears to be spam' if result['is_spam'] else 'This email appears to be legitimate'
    })


@app.route('/batch_predict', methods=['POST'])
def batch_predict():
    """API endpoint for batch spam prediction."""
    data = request.json
    emails = data.get('emails', [])

    results = classifier.predict_batch(emails)

    return jsonify({
        'predictions': results,
        'spam_count': sum(1 for r in results if r['is_spam']),
        'ham_count': sum(1 for r in results if not r['is_spam'])
    })


if __name__ == '__main__':
    app.run(debug=True)
