                loading.style.display = 'none';

                const resultLabel = document.getElementById('resultLabel');
                const resultDetails = document.getElementById('resultDetails');
                const progressFill = document.getElementById('progressFill');

                if (data.is_spam) {
                    result.classList.add('spam');
                    result.classList.remove('ham');
                    resultLabel.textContent = '🚨 SPAM DETECTED';
                    progressFill.style.width = (data.spam_probability * 100) + '%';
                } else {
                    result.classList.remove('spam');
                    result.classList.add('ham');
                    resultLabel.textContent = '✓ LEGITIMATE EMAIL';
                    progressFill.style.width = ((1 - data.spam_probability) * 100) + '%';
                }

                resultDetails.innerHTML = `
                    <p><strong>Spam Probability:</strong> ${(data.spam_probability * 100).toFixed(1)}%</p>
                    <p><strong>Confidence:</strong> ${(data.confidence * 100).toFixed(1)}%</p>
                    <p><strong>Message:</strong> ${data.message}</p>
                `;

                result.style.display = 'block';
            } catch (error) {
                loading.style.display = 'none';
                alert('Error: ' + error.message);
            }
        });
    </script>
